import { Channel } from '../types';

// Updated Playlist URL
const PLAYLIST_URL = "https://raw.githubusercontent.com/vlmofworld/vlm.protv/refs/heads/main/vlmprotv.m3u";

export const fetchChannels = async (): Promise<Channel[]> => {
  const channels: Channel[] = [];

  // Helper to detect if a URL is likely a direct stream (VideoPlayer) or a webpage (Iframe)
  const isDirectStream = (url: string) => {
    const lower = url.toLowerCase();
    // Added .mpd for DASH support
    return lower.includes('.m3u8') || lower.includes('.mp4') || lower.includes('.mkv') || lower.includes('.ts') || lower.includes('.mpd');
  };

  try {
    const response = await fetch(`${PLAYLIST_URL}?t=${Date.now()}`);
    if (!response.ok) {
      throw new Error('Failed to fetch playlist');
    }
    const data = await response.text();
    const lines = data.split('\n');

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();
      if (line.startsWith('#EXTINF:')) {
        // Regex improved for better logo matching (case insensitive)
        const logoMatch = line.match(/tvg-logo=["']([^"']*)["']/i);
        const logo = logoMatch ? logoMatch[1] : undefined;

        const groupMatch = line.match(/group-title=["']([^"']*)["']/i);
        const groupTitle = groupMatch ? groupMatch[1] : 'Live TV';

        const lastCommaIndex = line.lastIndexOf(',');
        let name = 'Unknown Channel';
        if (lastCommaIndex !== -1) {
          name = line.substring(lastCommaIndex + 1).trim();
        } else {
          const parts = line.split(',');
          if (parts.length > 1) {
             name = parts[parts.length - 1].trim();
          }
        }
        name = name.replace(/^["']|["']$/g, '');

        const url = lines[i + 1]?.trim();

        if (url && url.startsWith('http')) {
          channels.push({
            id: `channel-${i}`,
            name: name,
            url: url,
            isIframe: !isDirectStream(url),
            category: groupTitle,
            logo: logo
          });
        }
      }
    }
  } catch (error) {
    console.error('Error fetching channels:', error);
  }

  return channels;
};

import React, { useEffect, useRef } from 'react';
import { VideoPlayerProps } from '../types';

// Declare global types for the libraries loaded via CDN
declare global {
  interface Window {
    Plyr: any;
    Hls: any;
    dashjs: any;
  }
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ src, poster }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const playerRef = useRef<any>(null);
  const hlsRef = useRef<any>(null);
  const dashRef = useRef<any>(null);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    // Destroy previous instances
    if (playerRef.current) {
      playerRef.current.destroy();
      playerRef.current = null;
    }
    if (hlsRef.current) {
      hlsRef.current.destroy();
      hlsRef.current = null;
    }
    if (dashRef.current) {
      dashRef.current.reset();
      dashRef.current = null;
    }

    const source = src;
    const isHLS = source.includes('.m3u8');
    const isDASH = source.includes('.mpd');

    // Default Plyr Configuration
    const defaultOptions = {
      autoplay: true,
      controls: [
        'play-large', // The large play button in the center
        'play', // Play/pause playback
        'fast-forward', // Fast forward by the seek time (default 10 seconds)
        'progress', // The progress bar and scrubber for playback and buffering
        'current-time', // The current time of playback
        'duration', // The full duration of the media
        'mute', // Toggle mute
        'volume', // Volume control
        'settings', // Settings menu
        'pip', // Picture-in-picture (currently Safari only)
        'airplay', // Airplay (currently Safari only)
        'fullscreen', // Toggle fullscreen
      ],
      settings: ['quality', 'speed', 'loop'],
      speed: { selected: 1, options: [0.5, 0.75, 1, 1.25, 1.5, 2] },
      keyboard: { focused: true, global: true },
      poster: poster,
      tooltips: { controls: true, seek: true },
      i18n: {
        speed: 'Speed',
        quality: 'Quality',
      },
    };

    const initPlyr = () => {
       if (window.Plyr) {
          playerRef.current = new window.Plyr(video, defaultOptions);
       }
    };

    if (isHLS) {
      if (window.Hls && window.Hls.isSupported()) {
        const hls = new window.Hls({
           maxBufferLength: 30, // Optimized for stability
           enableWorker: true,
        });
        hlsRef.current = hls;
        hls.loadSource(source);
        hls.attachMedia(video);

        hls.on(window.Hls.Events.MANIFEST_PARSED, () => {
           // Provide quality options to Plyr
           const availableQualities = hls.levels.map((l: any) => l.height);
           // Add 'Auto' (represented by 0 or undefined usually, but Plyr handles manual custom defaults)

           // For simple HLS integration, we usually let HLS handle switching automatically
           // but we still init Plyr for the UI.
           initPlyr();

           // Attempt playback
           video.play().catch(() => {});
        });

        // Error handling
        hls.on(window.Hls.Events.ERROR, function (event: any, data: any) {
          if (data.fatal) {
            switch (data.type) {
              case window.Hls.ErrorTypes.NETWORK_ERROR:
                hls.startLoad();
                break;
              case window.Hls.ErrorTypes.MEDIA_ERROR:
                hls.recoverMediaError();
                break;
              default:
                hls.destroy();
                break;
            }
          }
        });
      } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
        // Native HLS support (Safari)
        video.src = source;
        video.addEventListener('loadedmetadata', () => {
           initPlyr();
           video.play().catch(() => {});
        });
      }
    } else if (isDASH) {
       if (window.dashjs) {
          const dash = window.dashjs.MediaPlayer().create();
          dashRef.current = dash;
          dash.initialize(video, source, true); // true = autoplay

          // Dash settings for better live streaming
          dash.updateSettings({
              'streaming': {
                  'delay': {
                      'liveDelay': 3 // Lower latency for live
                  },
                  'abr': {
                      'autoSwitchBitrate': {
                          'video': true
                      }
                  }
              }
          });

          // Wait a tick then init Plyr
          setTimeout(() => {
             initPlyr();
          }, 100);
       }
    } else {
      // Standard MP4/WebM/Direct File
      video.src = source;
      initPlyr();
      // Auto play check
      video.addEventListener('canplay', () => {
         video.play().catch(() => {});
      });
    }

  }, [src, poster]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (playerRef.current) {
        playerRef.current.destroy();
      }
      if (hlsRef.current) {
        hlsRef.current.destroy();
      }
      if (dashRef.current) {
        dashRef.current.reset();
      }
    };
  }, []);

  return (
    <div className="w-full h-full bg-black relative shadow-2xl">
      <video
        ref={videoRef}
        className="plyr-react plyr"
        playsInline
        controls
        crossOrigin="anonymous"
        poster={poster}
      />
    </div>
  );
};

export default VideoPlayer;

import React, { useEffect, useRef } from 'react';
import { VideoPlayerProps } from '../types';

declare global {
  interface Window {
    Artplayer: any;
    Hls: any;
    dashjs: any;
  }
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ src, poster }) => {
  const artRef = useRef<HTMLDivElement>(null);
  const playerInstance = useRef<any>(null);

  useEffect(() => {
    if (!artRef.current) return;

    // Clean up existing instance if any
    if (playerInstance.current) {
      playerInstance.current.destroy(false);
    }

    // Determine stream type
    const isHLS = src.includes('.m3u8');
    const isDASH = src.includes('.mpd');

    // Initialize Artplayer
    const art = new window.Artplayer({
      container: artRef.current,
      url: src,
      poster: poster,
      volume: 1,
      isLive: true, // Optimizes UI for live streaming
      muted: false,
      autoplay: true,
      pip: true,
      autoSize: true,
      autoMini: true,
      screenshot: true,
      setting: true,
      loop: false,
      flip: true,
      playbackRate: true,
      aspectRatio: true,
      fullscreen: true,
      fullscreenWeb: true,
      subtitleOffset: true,
      miniProgressBar: true,
      mutex: true,
      backdrop: true,
      playsInline: true,
      autoPlayback: true,
      airplay: true,
      theme: '#10b981', // Emerald 500

      // Advanced integration for HLS
      customType: {
        m3u8: function (video: HTMLVideoElement, url: string, art: any) {
          if (window.Hls && window.Hls.isSupported()) {
            const hls = new window.Hls({
              maxBufferLength: 30, // Tweak for stability
              enableWorker: true,
            });
            hls.loadSource(url);
            hls.attachMedia(video);
            art.hls = hls;

            // Listen for quality levels to update settings
            hls.on(window.Hls.Events.MANIFEST_PARSED, (event: any, data: any) => {
               // Auto play
               art.play(); 
            });

            hls.on(window.Hls.Events.ERROR, function (event: any, data: any) {
                if (data.fatal) {
                  switch (data.type) {
                    case window.Hls.ErrorTypes.NETWORK_ERROR:
                      hls.startLoad();
                      break;
                    case window.Hls.ErrorTypes.MEDIA_ERROR:
                      hls.recoverMediaError();
                      break;
                    default:
                      hls.destroy();
                      break;
                  }
                }
            });

            art.on('destroy', () => hls.destroy());
          } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
            video.src = url;
            art.play();
          } else {
            art.notice.show = 'Unsupported playback format: m3u8';
          }
        },
        // Advanced integration for DASH
        mpd: function(video: HTMLVideoElement, url: string, art: any) {
            if (window.dashjs) {
                const player = window.dashjs.MediaPlayer().create();
                player.initialize(video, url, true);

                // Low latency settings for live TV
                player.updateSettings({
                    'streaming': {
                        'delay': { 'liveDelay': 3 },
                        'abr': { 'autoSwitchBitrate': { 'video': true } }
                    }
                });

                art.dash = player;
                art.on('destroy', () => player.reset());
            } else {
                art.notice.show = 'Unsupported playback format: dash';
            }
        }
      },

      // Custom Controls & Layers
      controls: [
        {
          position: 'right',
          html: 'Live',
          tooltip: 'Live Stream',
          style: {
             color: '#ef4444', // Red 500
             fontWeight: 'bold',
             fontSize: '12px',
             pointerEvents: 'none'
          }
        }
      ]
    });

    // Error handling listener
    art.on('error', (error: any) => {
       console.log('Artplayer Error:', error);
       // Attempt to reload or recover if possible
       // art.play();
    });

    playerInstance.current = art;

    return () => {
      if (playerInstance.current) {
        playerInstance.current.destroy(false);
      }
    };
  }, [src, poster]);

  return (
    <div className="w-full h-full bg-black relative shadow-2xl group">
      {/* Artplayer Mount Point */}
      <div 
        ref={artRef} 
        className="w-full h-full absolute inset-0 z-10"
      />
    </div>
  );
};

