import React, { useEffect, useState, useMemo } from 'react';
import VideoPlayer from './components/VideoPlayer';
import ChannelItem from './components/ChannelItem';
import { fetchChannels } from './services/playlistService';
import { Channel } from './types';
import { MonitorPlay, Loader2, Search, AlertCircle, PlayCircle, Filter } from 'lucide-react';

const App: React.FC = () => {
  const [channels, setChannels] = useState<Channel[]>([]);
  const [currentChannel, setCurrentChannel] = useState<Channel | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [error, setError] = useState<string | null>(null);
  const [userIp, setUserIp] = useState<string | null>(null);

  // Security: Prevent context menu, dev tools shortcuts, and detect debugger
  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      e.preventDefault();
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      // Prevent F12, Ctrl+Shift+I, Ctrl+Shift+J, Ctrl+U, Ctrl+S
      if (
        e.key === 'F12' ||
        (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'J' || e.key === 'C')) ||
        (e.ctrlKey && e.key === 'u') ||
        (e.ctrlKey && e.key === 's')
      ) {
        e.preventDefault();
      }
    };

    document.addEventListener('contextmenu', handleContextMenu);
    document.addEventListener('keydown', handleKeyDown);

    // Anti-Debugging Mechanism
    // This interval forces a 'debugger' breakpoint if DevTools is open.
    // If DevTools is closed, the debugger statement is ignored by the browser engine.
    // If DevTools is open, the app freezes, preventing network inspection/sniffing.
    const antiDebugInterval = setInterval(() => {
      // Function constructor trick to avoid static analysis removal of debugger
      (function() { 
        try {
          (function(){return false;})['constructor']('debugger')();
        } catch(e) {}
      })();
    }, 1000);

    return () => {
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('keydown', handleKeyDown);
      clearInterval(antiDebugInterval);
    };
  }, []);

  // Fetch User IP for Ad Targeting Logic
  useEffect(() => {
    const fetchIp = async () => {
      try {
        const response = await fetch('https://api.ipify.org?format=json');
        if (response.ok) {
          const data = await response.json();
          setUserIp(data.ip);
        }
      } catch (e) {
        // IP fetch failed (adblocker or network), treat IP as unknown/null
      }
    };
    fetchIp();
  }, []);

  useEffect(() => {
    const loadData = async () => {
      try {
        const data = await fetchChannels();
        setChannels(data);
        if (data.length > 0) {
          setCurrentChannel(data[0]);
        }
      } catch (err) {
        // Log removed to prevent console inspection
        setError("Unable to load channel list. Please verify your connection.");
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, []);

  const handleChannelClick = (channel: Channel) => {
    // Adsterra Direct Link Logic
    const AD_LINK = "https://www.effectivegatecpm.com/jpbnyccx1t?key=103671d2be7bca0bd8e5de1ecdbde279";
    const STORAGE_KEY = "vlm_ad_tracker";

    try {
      const storedData = localStorage.getItem(STORAGE_KEY);
      const now = Date.now();
      let shouldShowAd = false;

      if (!storedData) {
        // No record (New device or first time) -> Show Ad
        shouldShowAd = true;
      } else {
        const { lastShown, ip } = JSON.parse(storedData);

        // Check if IP has changed (Same device, different IP)
        // If we couldn't fetch current IP (userIp is null), we assume it might be different or stick to time check.
        // Here we aggressively show ad if IP is different/unknown.
        if (userIp && ip !== userIp) {
          shouldShowAd = true;
        } else {
          // Same IP (or checking against unknown), check time (24 hours = 86400000 ms)
          const timeElapsed = now - lastShown;
          const twentyFourHours = 24 * 60 * 60 * 1000;

          if (timeElapsed > twentyFourHours) {
            shouldShowAd = true;
          }
        }
      }

      if (shouldShowAd) {
        window.open(AD_LINK, '_blank');
        // Update storage with new timestamp and current IP
        localStorage.setItem(STORAGE_KEY, JSON.stringify({
          lastShown: now,
          ip: userIp || 'unknown'
        }));
      }
    } catch (e) {
      // If error occurs in ad logic, ignore and proceed to play video
    }

    setCurrentChannel(channel);
    // Scroll to the top of the page so the sticky player is in view
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const categories = useMemo(() => {
