import React, { useEffect, useState, useMemo } from 'react';
import VideoPlayer from './components/VideoPlayer';
import ChannelItem from './components/ChannelItem';
import { fetchChannels } from './services/playlistService';
import { Channel } from './types';
import { MonitorPlay, Loader2, Search, AlertCircle, PlayCircle, Filter } from 'lucide-react';

const App: React.FC = () => {
  const [channels, setChannels] = useState<Channel[]>([]);
  const [currentChannel, setCurrentChannel] = useState<Channel | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [error, setError] = useState<string | null>(null);
  const [userIp, setUserIp] = useState<string | null>(null);

  // Security: Prevent context menu, dev tools shortcuts, and detect debugger
  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      e.preventDefault();
    };

    const handleKeyDown = (e: KeyboardEvent) => {
      // Prevent F12, Ctrl+Shift+I, Ctrl+Shift+J, Ctrl+U, Ctrl+S
      if (
        e.key === 'F12' ||
        (e.ctrlKey && e.shiftKey && (e.key === 'I' || e.key === 'J' || e.key === 'C')) ||
        (e.ctrlKey && e.key === 'u') ||
        (e.ctrlKey && e.key === 's')
      ) {
        e.preventDefault();
      }
    };

    document.addEventListener('contextmenu', handleContextMenu);
    document.addEventListener('keydown', handleKeyDown);

    // Anti-Debugging Mechanism
    const antiDebugInterval = setInterval(() => {
      (function() { 
        try {
          (function(){return false;})['constructor']('debugger')();
        } catch(e) {}
      })();
    }, 1000);

    return () => {
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('keydown', handleKeyDown);
      clearInterval(antiDebugInterval);
    };
  }, []);

  // Fetch User IP for Ad Targeting Logic
  useEffect(() => {
    const fetchIp = async () => {
      try {
        const response = await fetch('https://api.ipify.org?format=json');
        if (response.ok) {
          const data = await response.json();
          setUserIp(data.ip);
        }
      } catch (e) {
        // IP fetch failed, treat as unknown
      }
    };
    fetchIp();
  }, []);

  useEffect(() => {
    const loadData = async () => {
      try {
        const data = await fetchChannels();
        setChannels(data);
        if (data.length > 0) {
          setCurrentChannel(data[0]);
        }
      } catch (err) {
        setError("Unable to load channel list. Please verify your connection.");
      } finally {
        setIsLoading(false);
      }
    };

    loadData();
  }, []);

  const handleChannelClick = (channel: Channel) => {
    // Adsterra Direct Link Logic
    const AD_LINK = "https://www.effectivegatecpm.com/jpbnyccx1t?key=103671d2be7bca0bd8e5de1ecdbde279";
    const STORAGE_KEY = "vlm_ad_tracker";

    try {
      const storedData = localStorage.getItem(STORAGE_KEY);
      const now = Date.now();
      let shouldShowAd = false;

      if (!storedData) {
        // Rule 3: New device (no local storage) -> Show Ad
        // Also covers first time visit
        shouldShowAd = true;
      } else {
        const { lastShown, ip: storedIp } = JSON.parse(storedData);

        // Rule 2: Same device, IP changed
        // If userIp is available and differs from stored IP, show ad and reset timer
        if (userIp && storedIp !== userIp) {
          shouldShowAd = true;
        } else {
          // Rule 1: Same device, Same IP -> Check 24h limit
          const timeElapsed = now - lastShown;
          const twentyFourHours = 24 * 60 * 60 * 1000;

          if (timeElapsed > twentyFourHours) {
            shouldShowAd = true;
          }
        }
      }

      if (shouldShowAd) {
        window.open(AD_LINK, '_blank');
        // Start/Reset 24-hour countdown and update IP
        localStorage.setItem(STORAGE_KEY, JSON.stringify({
          lastShown: now,
          ip: userIp || 'unknown'
        }));
      }
    } catch (e) {
      // Ignore errors in ad logic to not disrupt user experience
    }

    setCurrentChannel(channel);
    // Scroll to the top of the page so the sticky player is in view
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const categories = useMemo(() => {
    // Use Set to preserve the order of appearance from the playlist
    const uniqueCats = Array.from(new Set(channels.map(c => c.category || 'Live TV')));
    return ['All', ...uniqueCats];
  }, [channels]);

  const filteredChannels = channels.filter(c => {
    const matchesCategory = selectedCategory === 'All' || c.category === selectedCategory;
    return matchesCategory;
  });

  return (
    <div className="min-h-screen bg-[#0f0f0f] text-white relative font-sans select-none">

      {/* Branding Header */}
      <header className="relative z-50 bg-[#0f0f0f] border-b border-white/5">
        <div className="w-full px-4 lg:px-6 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2 group cursor-pointer">
            <MonitorPlay className="text-emerald-500 w-6 h-6" />
            <div className="flex flex-col">
              <h1 className="text-lg font-black tracking-tighter text-white leading-none">
                VLM <span className="text-emerald-500">PRO TV</span>
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-6">
             <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-[#222] border border-white/10">
                <span className="relative flex h-2 w-2">
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-red-600"></span>
                </span>
                <span className="text-[10px] font-bold text-white uppercase tracking-wider">Live</span>
             </div>
          </div>
        </div>
      </header>

      {/* Sticky Container */}
      <div className="sticky top-0 z-50 bg-[#0f0f0f] shadow-xl">

        {/* Video Player Section */}
        <div className="w-full bg-black">
          <div className="w-full aspect-video max-h-[70vh] mx-auto relative bg-black">
            {isLoading ? (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-4 bg-zinc-900">
                <Loader2 className="w-12 h-12 animate-spin text-emerald-500" />
                <p className="font-bold text-sm tracking-widest text-zinc-500">LOADING STREAM</p>
              </div>
            ) : currentChannel ? (
              <>
                {currentChannel.isIframe ? (
                  <iframe 
                    title={currentChannel.name}
                    src={currentChannel.url} 
                    className="w-full h-full border-0 md:pointer-events-auto"
                    allowFullScreen
                    scrolling="no"
                    referrerPolicy="no-referrer"
                    sandbox="allow-forms allow-scripts allow-same-origin allow-popups allow-presentation"
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                  />
                ) : (
                  <VideoPlayer 
                    src={currentChannel.url} 
                    poster="https://i.ibb.co.com/67nQm2Ns/vlmprotv.png" 
                  />
                )}
              </>
            ) : (
              <div className="w-full h-full flex flex-col items-center justify-center text-slate-600 bg-zinc-900">
                <PlayCircle className="w-16 h-16 mb-4 opacity-20" />
                <p className="text-lg font-medium">Select a channel to begin</p>
              </div>
            )}
          </div>
        </div>

        {/* Category Bar */}
        <div className="w-full px-4 lg:px-6 py-3 bg-[#0f0f0f] border-b border-white/5 shadow-md">
           <div className="flex items-center gap-3 overflow-x-auto pb-1 scrollbar-thin">
            <div className="flex items-center justify-center min-w-[32px] h-[32px] rounded-full bg-zinc-900 border border-white/10 text-emerald-500 shrink-0">
               <Filter className="w-4 h-4" />
            </div>
            {categories.map((cat) => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`
                  px-4 py-1.5 rounded-full text-[11px] font-bold uppercase tracking-wider whitespace-nowrap transition-all border shrink-0
                  ${selectedCategory === cat 
                    ? 'bg-white text-black border-white shadow-sm' 
                    : 'bg-[#222] text-zinc-400 border-transparent hover:bg-[#333] hover:text-white'
                  }
                `}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <main className="container mx-auto px-4 lg:px-6 py-6 relative z-10 max-w-[1600px]">

        {/* Error Notification */}
        {error && (
          <div className="bg-red-900/20 border border-red-500/20 text-red-200 p-4 rounded-lg flex items-center gap-3 mb-8">
            <AlertCircle className="w-5 h-5 text-red-500" />
            <span className="font-medium">{error}</span>
          </div>
        )}

        {/* Channel Grid */}
        <div className="min-h-[300px]">
          {filteredChannels.length > 0 ? (
            <div className="grid grid-cols-4 sm:grid-cols-5 md:grid-cols-6 lg:grid-cols-7 xl:grid-cols-8 gap-4 sm:gap-6">
              {filteredChannels.map((channel) => (
                <ChannelItem 
                  key={channel.id} 
                  channel={channel} 
                  isActive={currentChannel?.id === channel.id} 
                  onClick={handleChannelClick} 
                />
              ))}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center py-20 text-zinc-700">
              <Search className="w-10 h-10 mb-3 opacity-50" />
              <p className="text-sm font-bold uppercase">No channels found</p>
              <button 
                onClick={() => {
                  setSelectedCategory('All');
                }}
                className="mt-4 px-4 py-1.5 text-[10px] font-bold uppercase bg-zinc-900 hover:bg-zinc-800 text-white rounded-md transition-colors"
              >
                Clear Filters
              </button>
            </div>
          )}
        </div>
      </main>

      <footer className="border-t border-white/5 bg-black mt-12 py-8 relative z-10">
        <div className="container mx-auto px-6 text-center">
          <p className="text-zinc-700 text-[10px] mb-2 uppercase tracking-widest">
            VLM PRO TV &copy; 2026
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

