    const { token } = req.params;

    if (!token || !token.includes('.')) {
        return res.status(403).send('Invalid Token Format');
    }

    const [data, signature] = token.split('.');

    // 1. Verify Signature
    const expectedSignature = crypto
        .createHmac('sha256', SECRET_KEY)
        .update(data)
        .digest('base64url');

    if (signature !== expectedSignature) {
        return res.status(403).send('Access Denied: Invalid Signature');
    }

    // 2. Decode Payload & Validate Expiry/IP
    try {
        const payload = JSON.parse(Buffer.from(data, 'base64url').toString());

        if (Date.now() > payload.exp) {
            return res.status(410).send('Link Expired');
        }

        // Optional: IP Validation (Strict Mode)
        // const currentIp = req.headers['x-forwarded-for'] || req.socket.remoteAddress || '127.0.0.1';
        // if (payload.ip !== currentIp) return res.status(403).send('IP Mismatch');

        // 3. Pipe the Stream
        const streamResponse = await axios({
            method: 'get',
            url: payload.url,
            responseType: 'stream',
            headers: {
                // Mimic a browser to avoid some hotlink protections
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
