import { Channel } from '../types';

// Configuration
const PROXY_PLAYLIST_URL = "http://localhost:5000/playlist";
const DIRECT_PLAYLIST_URL = "https://raw.githubusercontent.com/vlmofworld/vlm.protv/main/vlmprotv.m3u";

export const fetchChannels = async (): Promise<Channel[]> => {
  const channels: Channel[] = [];

  // Helper to detect if a URL is likely a direct stream (VideoPlayer) or a webpage (Iframe)
  // Updated to include 'video.m3u8' used by the proxy or query parameters
  const isDirectStream = (url: string) => {
    const lower = url.toLowerCase();
    return lower.includes('.m3u8') || 
           lower.includes('.mp4') || 
           lower.includes('.mkv') || 
           lower.includes('.ts') || 
           lower.includes('.mpd') ||
           lower.includes('stream/'); // Detect our proxy pattern
  };

  let playlistData = '';

  try {
    // 1. Attempt to fetch from the Secure Middleware Proxy
    const response = await fetch(PROXY_PLAYLIST_URL);
    if (!response.ok) throw new Error("Proxy unreachable");
    playlistData = await response.text();
    // console.log("Loaded via Proxy");
  } catch (proxyError) {
    // 2. Fallback to Direct Source if Proxy is down (ensures offline/demo functionality)
    console.warn("Secure Proxy unavailable, falling back to direct source.");
    try {
        const timestamp = new Date().getTime();
        const response = await fetch(`${DIRECT_PLAYLIST_URL}?nocache=${timestamp}`);
        if (!response.ok) throw new Error('Failed to fetch playlist');
        playlistData = await response.text();
    } catch (directError) {
        console.error('Error fetching channels:', directError);
        return [];
    }
  }

  // Parse Lines
  const lines = playlistData.split('\n');

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line.startsWith('#EXTINF:')) {
      const logoMatch = line.match(/tvg-logo=["']([^"']*)["']/i);
      const logo = logoMatch ? logoMatch[1] : undefined;

      const groupMatch = line.match(/group-title=["']([^"']*)["']/i);
      const groupTitle = groupMatch ? groupMatch[1] : 'Live TV';

      const lastCommaIndex = line.lastIndexOf(',');
      let name = 'Unknown Channel';
      if (lastCommaIndex !== -1) {
        name = line.substring(lastCommaIndex + 1).trim();
      } else {
        const parts = line.split(',');
        if (parts.length > 1) {
            name = parts[parts.length - 1].trim();
        }
      }
      name = name.replace(/^["']|["']$/g, '');

      const url = lines[i + 1]?.trim();

      if (url && url.startsWith('http')) {
        channels.push({
          id: `channel-${i}`,
          name: name,
          url: url,
          isIframe: !isDirectStream(url),
          category: groupTitle,
          logo: logo
        });
      }
    }
  }

  return channels;
};

