async function handlePlaylist(request) {
  // Validate Security
  if (!isRequestAllowed(request)) {
    return new Response("Forbidden", { status: 403 });
  }

  try {
    const response = await fetch(SOURCE_PLAYLIST_URL);
    const text = await response.text();
    const lines = text.split("\n");

    // Get Request Data
    const clientIp = request.headers.get("CF-Connecting-IP") || "0.0.0.0";
    const workerUrl = new URL(request.url).origin;

    const modifiedLines = lines.map((line) => {
      const trimmed = line.trim();
      if (trimmed.startsWith("http")) {
        const token = generateToken(trimmed, clientIp);
        return `${workerUrl}/stream?token=${token}`;
      }
      return line;
    });

    return new Response(modifiedLines.join("\n"), {
      headers: {
        "Content-Type": "audio/x-mpegurl",
        "Access-Control-Allow-Origin": "*", // Allow your frontend
      },
    });
  } catch (err) {
    return new Response("#EXTM3U\n#EXTINF:-1,Error\nhttp://localhost/error", {
      headers: { "Content-Type": "audio/x-mpegurl" },
    });
  }
}

async function handleStream(request, url) {
  const token = url.searchParams.get("token");
  if (!token) return new Response("Missing Token", { status: 403 });

  // 1. Verify Token
  const payload = verifyToken(token);
  if (!payload) return new Response("Invalid Token", { status: 403 });

  // 2. Check Expiry
  if (Date.now() > payload.exp) {
    return new Response("Token Expired", { status: 410 });
  }

  // 3. Check IP (Strict Mode)
  const clientIp = request.headers.get("CF-Connecting-IP");
  // if (clientIp && payload.ip !== clientIp) {
  //   return new Response("IP Mismatch", { status: 403 });
  // }

  // 4. Relay Stream
  // Cloudflare fetch acts as a proxy automatically
  const originalResponse = await fetch(payload.url, {
    headers: {
      "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36"
    }
  });

  // Create a new response to mask the origin headers if necessary
  const newResponse = new Response(originalResponse.body, originalResponse);
  newResponse.headers.set("Access-Control-Allow-Origin", "*");
  return newResponse;
}

// --- HELPERS ---

function isRequestAllowed(request) {
  if (!ALLOWED_REFERER) return true;
  const referer = request.headers.get("Referer");
  return referer && referer.includes(ALLOWED_REFERER);
}

function generateToken(url, ip) {
  const expiry = Date.now() + 2 * 60 * 60 * 1000; // 2 hours
  const data = JSON.stringify({ url, ip, exp: expiry });
  const encoded = btoa(data); // Base64
  const signature = hmacSha256(encoded, SECRET_KEY);
  return `${encoded}.${signature}`;
}

function verifyToken(token) {
  const parts = token.split(".");
  if (parts.length !== 2) return null;
  const [encoded, signature] = parts;

  const expectedSig = hmacSha256(encoded, SECRET_KEY);
  if (signature !== expectedSig) return null;

  try {
    return JSON.parse(atob(encoded));
  } catch (e) {
    return null;
  }
}

// Simple HMAC for Cloudflare Workers (Web Crypto API)
// Note: This is a synchronous approximation for demo. 
// In a real worker, use crypto.subtle.sign (async).
// For simplicity in this snippet, we use a simple hash of salt+data.
function hmacSha256(data, secret) {
    // In real production, use await crypto.subtle...
    // This is a placeholder logic for the structure.
    let hash = 0;
    const str = data + secret;
    for (let i = 0; i < str.length; i++) {
        const char = str.charCodeAt(i);
        hash = (hash << 5) - hash + char;
        hash = hash & hash;
    }
    return Math.abs(hash).toString(16);
}

