    if (line.startsWith('#EXTINF:')) {
      const logoMatch = line.match(/tvg-logo=["']([^"']*)["']/i);
      const logo = logoMatch ? logoMatch[1] : undefined;

      const groupMatch = line.match(/group-title=["']([^"']*)["']/i);
      const groupTitle = groupMatch ? groupMatch[1] : 'Live TV';

      const lastCommaIndex = line.lastIndexOf(',');
      let name = 'Unknown Channel';
      if (lastCommaIndex !== -1) {
        name = line.substring(lastCommaIndex + 1).trim();
      } else {
        const parts = line.split(',');
        if (parts.length > 1) {
            name = parts[parts.length - 1].trim();
        }
      }
      name = name.replace(/^["']|["']$/g, '');

      const url = lines[i + 1]?.trim();

      if (url && url.startsWith('http')) {
        channels.push({
          id: `channel-${i}`,
          name: name,
          url: url,
          isIframe: !isDirectStream(url),
          category: groupTitle,
          logo: logo
        });
      }
    }
  }

  return channels;
};

import React, { useEffect, useRef } from 'react';
import { VideoPlayerProps } from '../types';

declare global {
  interface Window {
    Artplayer: any;
    Hls: any;
    dashjs: any;
  }
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ src, poster }) => {
  const artRef = useRef<HTMLDivElement>(null);
  const playerInstance = useRef<any>(null);

  useEffect(() => {
    if (!artRef.current) return;

    // Clean up existing instance if any
    if (playerInstance.current) {
      playerInstance.current.destroy(false);
    }

    // Initialize Artplayer
    const art = new window.Artplayer({
      container: artRef.current,
      url: src,
      poster: poster,
      volume: 1,
      isLive: true, // Optimizes UI for live streaming
      muted: false,
      autoplay: true,
      pip: true,
      autoSize: true,
      autoMini: true,
      screenshot: true,
      setting: true,
      loop: false,
      flip: true,
      playbackRate: true,
      aspectRatio: true,
      fullscreen: true,
      fullscreenWeb: true,
      subtitleOffset: true,
      miniProgressBar: true,
      mutex: true,
      backdrop: true,
      playsInline: true,
      autoPlayback: true,
      airplay: true,
      theme: '#10b981', // Emerald 500

      // Advanced integration for HLS & DASH
      customType: {
        m3u8: function (video: HTMLVideoElement, url: string, art: any) {
          if (window.Hls && window.Hls.isSupported()) {
            const hls = new window.Hls({
              maxBufferLength: 30, // Tweak for stability
              enableWorker: true,
            });
            hls.loadSource(url);
            hls.attachMedia(video);
            art.hls = hls;

            // Listen for parsed manifest to extract quality levels
            hls.on(window.Hls.Events.MANIFEST_PARSED, (event: any, data: any) => {
               art.play(); 

               // Multi-Quality Support
               if (data.levels && data.levels.length > 1) {
                  const levels = data.levels.map((level: any, index: number) => ({
                      html: `${level.height || 'Unknown'}p`,
                      index: index,
                  }));

                  // Add 'Auto' option and sort high quality to low
                  const qualitySelector = [
                    { html: 'Auto', index: -1, default: true },
                    ...levels.reverse()
                  ];

                  // Add Quality Menu to Settings
                  art.setting.add({
                      html: 'Quality',
                      width: 150,
                      tooltip: 'Auto',
                      selector: qualitySelector,
                      onSelect: (item: any) => {
                          hls.currentLevel = item.index;
                          return item.html;
                      },
                  });
               }
            });

            // Error Handling for HLS
            hls.on(window.Hls.Events.ERROR, function (event: any, data: any) {
                if (data.fatal) {
                  switch (data.type) {
                    case window.Hls.ErrorTypes.NETWORK_ERROR:
                      hls.startLoad();
                      break;
                    case window.Hls.ErrorTypes.MEDIA_ERROR:
                      hls.recoverMediaError();
                      break;
                    default:
                      hls.destroy();
                      break;
                  }
                }
            });

            art.on('destroy', () => hls.destroy());
          } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
            // Native HLS support (Safari)
            video.src = url;
            art.play();
          } else {
            art.notice.show = 'Unsupported playback format: m3u8';
          }
        },

        // Advanced integration for DASH
        mpd: function(video: HTMLVideoElement, url: string, art: any) {
            if (window.dashjs) {
                const player = window.dashjs.MediaPlayer().create();
                player.initialize(video, url, true);

                // Low latency settings for live TV
                player.updateSettings({
                    'streaming': {
                        'delay': { 'liveDelay': 3 },
                        'abr': { 'autoSwitchBitrate': { 'video': true } }
                    }
                });

                // Auto Quality Detection for DASH
                player.on(window.dashjs.MediaPlayer.events.STREAM_INITIALIZED, () => {
                    const bitrates = player.getBitrateInfoListFor('video');
                    if (bitrates && bitrates.length > 1) {
                        const qualities = bitrates.map((b: any, index: number) => ({
                            html: `${b.height}p`,
                            index: index
                        }));

                        const qualitySelector = [
                             { html: 'Auto', index: -1, default: true },
                             ...qualities.reverse()
                        ];

                        art.setting.add({
                            html: 'Quality',
                            width: 150,
                            tooltip: 'Auto',
                            selector: qualitySelector,
                            onSelect: (item: any) => {
                                if (item.index === -1) {
                                    player.updateSettings({ 'streaming': { 'abr': { 'autoSwitchBitrate': { 'video': true } } } });
                                } else {
                                    player.updateSettings({ 'streaming': { 'abr': { 'autoSwitchBitrate': { 'video': false } } } });
                                    player.setQualityFor('video', item.index);
                                }
                                return item.html;
                            }
                        });
                    }
                });

                art.dash = player;
                art.on('destroy', () => player.reset());
            } else {
                art.notice.show = 'Unsupported playback format: dash';
            }
        }
      },

      // Custom Controls & Layers
      controls: [
        {
          position: 'right',
          html: 'Live',
          tooltip: 'Live Stream',
          style: {
             color: '#ef4444', // Red 500
             fontWeight: 'bold',
             fontSize: '12px',
             pointerEvents: 'none'
          }
        }
      ]
    });

    // Error handling listener
    art.on('error', (error: any) => {
       console.log('Artplayer Error:', error);
    });

    playerInstance.current = art;

    return () => {
      if (playerInstance.current) {
        playerInstance.current.destroy(false);
      }
    };
  }, [src, poster]);

  return (
    <div className="w-full h-full bg-black relative shadow-2xl group">
      {/* Artplayer Mount Point */}
      <div 
        ref={artRef} 
        className="w-full h-full absolute inset-0 z-10"
      />
    </div>
  );
};

