import React, { useEffect, useRef } from 'react';
import { VideoPlayerProps } from '../types';

declare global {
  interface Window {
    Plyr: any;
    Hls: any;
  }
}

const VideoPlayer: React.FC<VideoPlayerProps> = ({ src, poster }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const playerRef = useRef<any>(null);
  const hlsRef = useRef<any>(null);

  useEffect(() => {
    // Cleanup previous instances
    const destroyPlayer = () => {
      if (hlsRef.current) {
        hlsRef.current.destroy();
        hlsRef.current = null;
      }
      if (playerRef.current) {
        playerRef.current.destroy();
        playerRef.current = null;
      }
    };

    if (!videoRef.current) return;
    destroyPlayer();

    const video = videoRef.current;

    // Plyr Default Options
    const defaultOptions = {
      controls: [
        'play-large', 'play', 'fast-forward', 'progress', 
        'current-time', 'duration', 'mute', 'volume', 
        'captions', 'settings', 'pip', 'airplay', 'fullscreen'
      ],
      settings: ['quality', 'speed', 'loop'],
      speed: { selected: 1, options: [0.5, 0.75, 1, 1.25, 1.5, 2] },
      autoplay: true,
      poster: poster,
      tooltips: { controls: true, seek: true },
      i18n: {
        quality: 'Quality',
        speed: 'Speed',
      }
    };

    // Check if HLS is supported and the source is an HLS stream
    const isHls = src.includes('.m3u8') || src.includes('/stream');

    if (isHls && window.Hls && window.Hls.isSupported()) {
      const hls = new window.Hls({
        maxBufferLength: 30,
        enableWorker: true,
      });
      hlsRef.current = hls;

      hls.loadSource(src);
      hls.attachMedia(video);

      hls.on(window.Hls.Events.MANIFEST_PARSED, (event: any, data: any) => {
        // Extract available quality levels
        const availableQualities = hls.levels.map((l: any) => l.height);

        // Add '0' for Auto mode if multiple qualities exist
        // Note: Plyr treats 0 as a custom label if mapped in i18n, usually used for Auto
        const qualityOptions = availableQualities.length > 1 
            ? [0, ...availableQualities] 
            : availableQualities;

        // Initialize Plyr with dynamic quality settings
        const player = new window.Plyr(video, {
          ...defaultOptions,
          quality: {
            default: 0, // Auto by default
            options: qualityOptions,
            forced: true,
            onChange: (newQuality: number) => {
              if (newQuality === 0) {
                hls.currentLevel = -1; // -1 represents Auto in HLS.js
              } else {
                // Find index of the selected height
                hls.levels.forEach((level: any, levelIndex: number) => {
                  if (level.height === newQuality) {
                    hls.currentLevel = levelIndex;
                  }
                });
              }
            },
          },
          i18n: {
            qualityLabel: {
              0: 'Auto',
            },
          },
        });

        playerRef.current = player;

        // Ensure autoplay works smoothly
        const playPromise = player.play();
        if (playPromise !== undefined) {
            playPromise.catch(() => {
                // Autoplay blocked handling if needed
                player.muted = true;
                player.play();
            });
        }
      });

      // HLS Error Handling
      hls.on(window.Hls.Events.ERROR, function (event: any, data: any) {
        if (data.fatal) {
          switch (data.type) {
            case window.Hls.ErrorTypes.NETWORK_ERROR:
              hls.startLoad();
              break;
            case window.Hls.ErrorTypes.MEDIA_ERROR:
              hls.recoverMediaError();
              break;
            default:
              destroyPlayer();
              break;
          }
        }
      });

    } else {
      // Native HLS (Safari) or standard MP4
      if (video.canPlayType('application/vnd.apple.mpegurl') && isHls) {
        video.src = src;
      } else {
        video.src = src;
      }

      const player = new window.Plyr(video, defaultOptions);
      playerRef.current = player;

      const playPromise = player.play();
        if (playPromise !== undefined) {
            playPromise.catch(() => {
                player.muted = true;
                player.play();
            });
        }
    }

    return destroyPlayer;
  }, [src, poster]);

  return (
    <div className="w-full h-full bg-black relative shadow-2xl group overflow-hidden">
      <video
        ref={videoRef}
        className="plyr-video w-full h-full object-contain"
        crossOrigin="anonymous"
        playsInline
      />
    </div>
  );
};

