const VideoPlayer: React.FC<VideoPlayerProps> = ({ src, poster }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const playerRef = useRef<any>(null);
  const hlsRef = useRef<any>(null);

  useEffect(() => {
    // 1. CLEANUP: Destroy previous instances to prevent leaks/conflicts
    const destroyPlayer = () => {
      if (playerRef.current) {
        playerRef.current.destroy();
        playerRef.current = null;
      }
      if (hlsRef.current) {
        hlsRef.current.destroy();
        hlsRef.current = null;
      }
    };

    if (!videoRef.current) return;
    destroyPlayer();

    const video = videoRef.current;

    // 2. PLYR CONFIGURATION
    const plyrOptions = {
      controls: [
        'play-large', 'play', 'fast-forward', 'progress',
        'current-time', 'duration', 'mute', 'volume',
        'captions', 'settings', 'pip', 'airplay', 'fullscreen'
      ],
      settings: ['quality', 'speed', 'loop'],
      speed: { selected: 1, options: [0.5, 0.75, 1, 1.25, 1.5, 2] },
      autoplay: true,
      poster: poster,
      ratio: '16:9',
      tooltips: { controls: true, seek: true },
      i18n: {
        quality: 'Quality',
        speed: 'Speed',
        qualityLabel: {
          0: 'Auto' // Maps value 0 to "Auto" text in menu
        }
      }
    };

    // 3. SOURCE HANDLING
    const isHls = src.includes('.m3u8') || src.includes('/stream');

    if (isHls && window.Hls && window.Hls.isSupported()) {
      // --- HLS STREAMING SETUP ---
      const hls = new window.Hls({
        maxBufferLength: 30,
        enableWorker: true,
      });
      hlsRef.current = hls;

      hls.loadSource(src);
      hls.attachMedia(video);

      hls.on(window.Hls.Events.MANIFEST_PARSED, (event: any, data: any) => {
        // Extract available resolutions (heights)
        const availableQualities = hls.levels.map((l: any) => l.height);

        // Setup Quality Options: Add '0' (Auto) if multiple levels exist
        let options = availableQualities;
        if (availableQualities.length > 1) {
           // Filter unique values and sort descending (High to Low)
           const unique = [...new Set(availableQualities)].sort((a: any, b: any) => b - a);
           options = [0, ...unique];
        }

        // Initialize Plyr with Quality Config
        playerRef.current = new window.Plyr(video, {
          ...plyrOptions,
          quality: {
            default: 0,
            options: options,
            forced: true,
            onChange: (newQuality: number) => {
              if (newQuality === 0) {
                hls.currentLevel = -1; // -1 triggers Auto-Level in HLS.js
              } else {
                // Find index of the selected height
                const levelIndex = hls.levels.findIndex((l: any) => l.height === newQuality);
                if (levelIndex !== -1) {
                   hls.currentLevel = levelIndex;
                }
              }
            }
          }
        });

        // Autoplay Handling
        try {
            const playPromise = playerRef.current.play();
            if (playPromise) {
                playPromise.catch(() => {
                    // If autoplay blocked, mute and try again
                    playerRef.current.muted = true;
                    playerRef.current.play();
                });
            }
        } catch (e) {
            console.log("Autoplay check failed");
        }
      });

      // HLS Error Recovery
      hls.on(window.Hls.Events.ERROR, (event: any, data: any) => {
        if (data.fatal) {
          switch (data.type) {
            case window.Hls.ErrorTypes.NETWORK_ERROR:
              hls.startLoad();
              break;
            case window.Hls.ErrorTypes.MEDIA_ERROR:
              hls.recoverMediaError();
              break;
            default:
              destroyPlayer();
              break;
          }
        }
      });

    } else {
      // --- STANDARD MP4 / NATIVE HLS SETUP (Safari) ---
      video.src = src;
      playerRef.current = new window.Plyr(video, plyrOptions);

      try {
          const playPromise = playerRef.current.play();
          if (playPromise) {
              playPromise.catch(() => {
                  playerRef.current.muted = true;
                  playerRef.current.play();
              });
          }
      } catch (e) {}
    }

    return destroyPlayer;
  }, [src, poster]);

  return (
    <div className="w-full h-full bg-black relative shadow-2xl overflow-hidden rounded-xl group">
      <video
        ref={videoRef}
        crossOrigin="anonymous"
        playsInline
        className="plyr-video w-full h-full object-contain"
      />
